sys_script_include.script:
var TaniumConfiguredSensorUtil = Class.create();
TaniumConfiguredSensorUtil.prototype = Object.extendsObject(x_taniu_tan_core.TaniumIntegrationCore, {

	/**
	 * Execute a specified Configured Sensor on an endpoint, and return the results in an
	 *  object with a node containing an array of columns, and another node containing
	 *  an array of row objects.
	 * Each row object consists of a node for each column (with the key to each node being
	 *  the name of that column).
	 * @param {GlideRecord} grConfiguredSensor - A GlideRecord positioned to the Configured
	 *  Sensor record for the specific Configured Sensor you'd like to execute against the
	 *  target endpoint and get the results for.
	 * @param {GlideRecord} grEndpoint - A GlideRecord positioned to the endpoint on which
	 *  you'd like to execute the specified Configured Sensor.
	 * @param {boolean} [useLiveData=true] - Set this argument to false in order to attempt
	 *  to retrieve cached data, which may be faster in some cases at the cost of returning
	 *  outdated data.
	 * @param {{}} [argsObj={}] - An optional object to pass into any Configured
	 *  Action Parameters that use an "advanced" scripted parameter value.
	 * This is not required, and in the vast majority of cases, will not be used.
	 * Default value: {}
	 * @param {boolean} [useGetNextPage=false] - Set this argument to true in order to override
	 *  using .queryAsync(), and use the old .getNextPage() method instead.
	 * @param {number} [minimumEndpointCount=1] - The minimum number of endpoints
	 *  that must be returned by the query before the query will be considered complete, and the
	 *  response will be returned by this method. If this value is set to 0 (or unspecified),
	 *  it will be ignored.
	 * When using the .getConfiguredSensorResults() method, since it queries only a single
	 *  endpoint, this argument should nearly always be set to 1 or omitted.
	 * This argument is only used when the useGetNextPage argument is set to false (its default).
	 * @param {number} [maxRetries=0] - The maximum number of times the query will be retried
	 *  before the result is returned. Each "poll" of the API using the refresh token, the query
	 *  will be retried until the query is complete (based on the other arguments specified for
	 *  this method) or until the maxRetries limit is reached. If this value is set to 0 (or
	 *  unspecified), it will be set to its default value which is 180 (3 minutes) divided by
	 *  the value of the maxWaitTimePerRequest argument.
	 * For example, if maxWaitTime is set to 3 (seconds), then maxRetries will be set to
	 *  180/3=60 polls by default, after which the response will be returned whether it's
	 *  completed or not.
	 * This argument is only used when the useGetNextPage argument is set to false (its default).
	 * @param {boolean} [executeAsync=false] - If set to true, the .executeAsync()  method of
	 *  RESTMessageV2  will be used instead of the .execute()  method. This may result in a
	 *  longer time between call and response but may be preferable if the total number of
	 *  requests is very high, which could otherwise bog down instance performance, though when
	 *  calling the TaniumConfiguredSensorUtil.getConfiguredSensorResults() method, this should
	 *  typically either be set to its default value (false) or unspecified.
	 * Note that this argument does not change whether this method itself is asynchronous; this
	 *  method does not accept a callback function. It only changes whether the RESTMessageV2
	 *  object is executed asynchronously within the instance. Server-side JavaScript code in
	 *  ServiceNow always executes "synchronously". See ServiceNow's API documentation on
	 *  .executeAsync() for more info.
	 * This argument is only used when the useGetNextPage argument is set to false (its default).
	 * @param {number} [maxWaitTimePerRequest=3] - The maximum time (in seconds) to wait for a
	 *  response from the Tanium API Gateway for each request. Never set this to a value greater
	 *  than ~25.
	 * This is the maximum amount of time to wait for a response from the Tanium API Gateway for
	 *  each request. The .queryAsync() method will make multiple requests until some condition
	 *  is met (based on the arguments provided), so this value will be multiplied by the
	 *  number of requests made. A shorter maxWaitTimePerRequest argument may result in a
	 *  faster response. A value of 0 will result in the default value of 5 being used, just as
	 *  if the argument was not provided. The default value of 5 seconds is recommended, but
	 *  any value between ~3 and 10 is a good range to use. Any values >= 30 will be ignored,
	 *  as that would result in a potential timeout.
	 * This argument is only used when the useGetNextPage argument is set to false (its default).
	 *
	 * @returns {{columns: [], rows: []}} - The results of the query in an object with a
	 *  node containing an array of columns, and another node containing an array of
	 *  row objects.
	 * Each row object consists of a node for each column (with the key to each node being
	 *  the name of that column).
	 * @since 1.2.0
	 */
	getConfiguredSensorResults: function(
		grConfiguredSensor,
		grEndpoint,
		useLiveData,
		argsObj,
		useGetNextPage,
		minimumEndpointCount,
		maxRetries,
		executeAsync,
		maxWaitTimePerRequest
	) {
		var objConfiguredParamValues, paramKey, paramValue, querySensorObj, queryResults;
		var gwQueryUtil = new x_taniu_tan_core.GatewayQueryUtil();
		var grSourceSensor = grConfiguredSensor.sensor.getRefRecord();
		var endpointSerial = grEndpoint.getValue('serial_number');

		//Set default values
		useGetNextPage = (useGetNextPage === true) ? useGetNextPage : false;
		minimumEndpointCount = (typeof minimumEndpointCount === 'number') ? minimumEndpointCount : 1;
		maxRetries = (typeof maxRetries === 'number') ? maxRetries : 0;
		executeAsync = (typeof executeAsync === 'boolean') ? executeAsync : false;
		maxWaitTimePerRequest = (typeof maxWaitTimePerRequest === 'number') ? maxWaitTimePerRequest : 0;

		if (!grSourceSensor.isValidRecord()) {
			throw new Error(
				'Invalid sensor used - Configured Sensor record with sys_id ' +
				grConfiguredSensor.getUniqueValue() + 'has a Sensor field that does not ' +
				'point to a valid record. Cannot retrieve Configured Sensor results.'
			);
		}

		//Set default values
		argsObj = (gs.nil(argsObj) || !argsObj) ? {} : argsObj;
		useLiveData = (gs.nil(useLiveData)) ? true : useLiveData;

		if (!endpointSerial) {
			//Provided endpoint has no serial number. This is required for the filter below, so
			// throw an error.
			throw new Error(
				'Cannot query the configured sensor "' + grConfiguredSensor.getDisplayValue() +
				'" because the provided endpoint "' + grEndpoint.getDisplayValue() +
				'" has no serial number. This is required in order to uniquely identify the ' +
				'specified endpoint within Tanium.'
			);
		}

		//Set whether to use live or cached data
		if (useLiveData) {
			gwQueryUtil.useLiveData(1);
		} else {
			gwQueryUtil.useCachedData();
		}
		gwQueryUtil.setPageSize(1);

		//Add filter to only query endpoints with the provided CI's serial number
		gwQueryUtil.addFilter('serialNumber', 'EQ', endpointSerial);

		querySensorObj = gwQueryUtil.addSensor(grSourceSensor.getValue('name'));

		//Get all configured parameters associated with this sensor
		objConfiguredParamValues = this._getAllConfiguredSensorParamValues(
			grConfiguredSensor.getUniqueValue(),
			grEndpoint,
			argsObj
		);

		//For each configured sensor param with a value, add it to the query sensor object.
		for (paramKey in objConfiguredParamValues) {
			//Prevent iteration into non-own properties
			if (!objConfiguredParamValues.hasOwnProperty(paramKey)) {
				continue;
			}

			paramValue = objConfiguredParamValues[paramKey];
			if (paramValue) {
				querySensorObj.addParam(paramKey, paramValue);
			}
		}

		queryResults = useGetNextPage ? gwQueryUtil.getNextPage() : gwQueryUtil.queryAsync(
			minimumEndpointCount,
			0, //Set minimumResponsePercent to default value
			maxRetries, //maxRetries
			executeAsync, //executeAsync
			1, //expectedCount
			maxWaitTimePerRequest //maxWaitTimePerRequest (seconds)
		);
		return gwQueryUtil._transformGatewayQueryResponse(
			queryResults
		);
	},

	/**
	 * Sync all Sensors and Sensor Parameters from Tanium into the Tanium Sensor and Sensor
	 *  Parameter tables.
	 * This method is called by the "Sync Tanium Sensors and Sensor Parameters" Scheduled Script.
	 * @since 1.2.0
	 */
	syncSensorsAndParameters: function() {
		var allSensors;

		allSensors = this._getAllSensorDetails();

		//Update any sensors in the Tanium Sensors table that need updating.
		//Delete any sensors in the table that weren't in this latest export.
		this._updateAndDeleteExistingSensors(allSensors);
		//NOTE: The above method modifies allSensors in-place, removing any that were updated
		// or deleted, so all sensor objects remaining in it should then be created.
		this._createAllMissingSensors(allSensors);

		return true;
	},

	/**
	 * Check if a Configured Sensor Parameter is valid.
	 * @param {GlideRecord} grCurrentConfiguredParam - A GlideRecord positioned to a specific
	 *  record in the Configured Sensor Parameter table that needs to have its value validated.
	 * @param {GlideRecord} [grCIToEvaluateWith=] - The CI against which to validate the
	 *  parameter. This is only necessary for validating scripted (advanced) Configured
	 *  Sensor Parameters.
	 * @returns {{validation_message: string, parameter_valid: boolean}} - An object containing
	 *  a parameter_valid node which contains a boolean indicating whether the parameter was
	 *  validated successfully, and a "validation_message" parameter which - if was not valid -
	 *  tells you why it wasn't.
	 * @since 1.2.0
	 */
	isConfiguredSensorParameterValid: function(grCurrentConfiguredParam, grCIToEvaluateWith) {
		var grSensorParam, paramValidationExpressions, configuredParamValue, validationResults;
		var cParamIsAdvanced = (grCurrentConfiguredParam.getValue('advanced') === '1');
		var responseObj = {
			"parameter_valid": false,
			"validation_message": ""
		};

		//If "Configured Sensor" or "Sensor parameter" field are empty, return false.
		if (
			grCurrentConfiguredParam.sensor_parameter.nil() ||
			grCurrentConfiguredParam.configured_sensor.nil()
		) {
			responseObj.parameter_valid = false;
			responseObj.validation_message = 'Either "Configured sensor" or "Sensor parameter" ' +
				'field is blank. Therefore, this parameter is not valid.';

			return responseObj;
		}

		if (cParamIsAdvanced && (typeof grCIToEvaluateWith === 'undefined')) {
			//If configured sensor param is advanced but CI is not specified, then just return true
			// since we can't evaluate the value of the advanced configured param without a CI.
			responseObj.parameter_valid = true;
			responseObj.validation_message = 'Configured Sensor Parameter is set to ' +
				'"Advanced", but a suitable CI GlideRecord was not passed in to the ' +
				'isConfiguredSensorParameterValid() method. Without this argument, we are ' +
				'unable to execute the advanced value script in order to evaluate whether ' +
				'the evaluated value would be valid; therefore, assuming validity by default.';

			return responseObj;
		}

		//Get configured sensor param value. If the configured param is advanced, it will evaluate
		// the value script; otherwise, it will return the "Value" field's contents.
		configuredParamValue = this._getConfiguredSensorParamValue(
			grCurrentConfiguredParam,
			grCIToEvaluateWith
		);

		//GlideRecord for the sensor parameter from which this configured param was created.
		grSensorParam = grCurrentConfiguredParam.sensor_parameter.getRefRecord();
		if (!grSensorParam.isValidRecord()) {
			throw new Error(
				'Invalid sensor Parameter used - Configured Sensor Parameter record with sys_id ' +
				grCurrentConfiguredParam.getUniqueValue() + 'has a Sensor Parameter field that ' +
				'does not point to a valid record.'
			);
		}

		if (grSensorParam.validation_expressions.nil()) {
			//If param has no validation expressions, return true.
			responseObj.parameter_valid = true;
			responseObj.validation_message = 'Parameter definition has no validation ' +
				'expressions associated with it. Thus, any value is valid (including blank).';

			return responseObj;
		}

		paramValidationExpressions = grSensorParam.getValue('validation_expressions');

		validationResults = this._doesSensorParamValuePassValidation(
			configuredParamValue,
			paramValidationExpressions
		);

		responseObj.parameter_valid = validationResults.valid;
		responseObj.validation_message = 'The Configured Parameter value "' +
			configuredParamValue + '"' + (validationResults.valid ? ' passed ' : ' did not pass ') +
			'the associated parameter\'s validation expression(s).';
		if (validationResults.help_string) {
			responseObj.validation_message += '\n' + validationResults.help_string;
		}

		return responseObj;
	},

	_getAllConfiguredSensorParamValues: function(configuredSensorID, grEndpoint, argsObj) {
		var paramKey, paramVal, grConfiguredSensorParam;
		var parameterValues = {};

		argsObj = (typeof argsObj === 'undefined') ? {} : argsObj;

		grConfiguredSensorParam = new GlideRecord('x_taniu_tan_core_configured_sensor_parameter');
		grConfiguredSensorParam.addQuery('configured_sensor', configuredSensorID);
		grConfiguredSensorParam.query();

		while (grConfiguredSensorParam.next()) {
			if (grConfiguredSensorParam.key.nil()) {
				//If configured sensor param has no key, then bail to the next loop.
				continue;
			}

			paramKey = grConfiguredSensorParam.getValue('key');
			paramVal = this._getConfiguredSensorParamValue(
				grConfiguredSensorParam,
				grEndpoint,
				argsObj
			);

			if (paramVal) {
				//Escape backslashes to cover our behinds.
				paramVal = paramVal.replaceAll('\\', '\\\\');
			}

			parameterValues[paramKey] = paramVal;
		}

		return parameterValues;
	},

	/**
	 * @param configuredParamValue
	 * @param validationExpressions
	 * @returns {{valid: boolean, help_string: string}}
	 * @private
	 */
	_doesSensorParamValuePassValidation: function(
		configuredParamValue,
		validationExpressions
	) {
		var i, expression, regexEvaluator, helpString;
		var responseObj = {
			"valid": true,
			"help_string": ""
		};


		if (!validationExpressions) {
			//If validationExpressions is falsy, assume validity. Return true.
			responseObj.valid = true;
			return responseObj;
		}

		try {
			validationExpressions = JSON.parse(validationExpressions);
		} catch(ex) {
			//If parse failed, just assume the param is valid and return true.
			responseObj.valid = true;
			return responseObj;
		}
		if (!validationExpressions || validationExpressions.length === 0) {
			//If no validation expressions found, return true.
			responseObj.valid = true;
			return responseObj;
		}

		for (i = 0; i < validationExpressions.length; i++) {
			//Skip to next loop if element has no expression property.
			if (!validationExpressions[i].hasOwnProperty('expression')) {
				continue;
			}
			expression = validationExpressions[i].expression.toString();
			regexEvaluator = new RegExp(expression);

			//If the value fails any of the tests in the array, return false.
			if (!regexEvaluator.test(configuredParamValue)) {
				responseObj.valid = false;

				if (validationExpressions[i].hasOwnProperty('helpString')) {
					helpString = validationExpressions[i].helpString;
					//If help string already has a value and the new validation expression
					// has a help string, add double-new-line separator.
					if (responseObj.help_string && helpString) {
						responseObj.help_string += ' \n\n';
					}

					//Add help string to the response Object
					responseObj.help_string += helpString;
				}
			}
		}

		//Default, return true
		return responseObj; //Default is valid:true with blank help_string node
	},

	/**
	 * Retrieve the value from the Configured Sensor Parameter in the
	 *  x_taniu_tan_core_configured_sensor_parameter table.
	 * If the parameter has a static string value, then that will be returned. If the "Advanced"
	 *  checkbox on the Configured Sensor Parameter record is checked, then the associated script
	 *  will be evaluated and the result will be returned instead.
	 * @param {GlideRecord} grConfiguredSensorParam - A GlideRecord on the
	 *  x_taniu_tan_core_configured_sensor_parameter table, positioned to the specific parameter
	 *  to get the value from.
	 * @param {GlideRecord} [grCurrentCI={}] - A CI to use in the evaluation of an advanced
	 *  configured parameter value script. This can be omitted if none of the parameters use this
	 *  value in their scripts.
	 * @param {Object} [argsObj={}] - Optionally specify an additional object to be passed in
	 *  to the value script, with some additional values in it that can be used when the script
	 *  is evaluated.
	 * @returns {String} - The value from either the "value" field of the Configured Sensor
	 *  Parameter record, OR the (stringified) result of the evaluation of the script from
	 *  the value_script field (if the Advanced field is set to true).
	 * @private
	 */
	_getConfiguredSensorParamValue: function(grConfiguredSensorParam, grCurrentCI, argsObj) {
		var gsEval, evalResult;
		grCurrentCI = (typeof grCurrentCI === 'undefined') ? {} : grCurrentCI;
		argsObj = (typeof argsObj != 'object') ? {} : argsObj;

		//If advanced is true, evaluate the script and return the result.
		if (grConfiguredSensorParam.getValue('advanced') === '1') {
			gsEval = new GlideScopedEvaluator();

			gsEval.putVariable('currentCI', grCurrentCI);
			gsEval.putVariable('argsObj', argsObj);

			//Considered wrapping this in a 'try/catch' block, but we actually want it to
			// hard-error if this fails, as we don't want the sensor query to continue until the
			// error is resolved.
			evalResult = gsEval.evaluateScript(
				grConfiguredSensorParam,
				'value_script'
			);

			//If evalResult is undefined, return blank string. Otherwise, return result.
			try {
				return ((typeof evalResult === 'undefined') || (evalResult === null)) ? '' : evalResult.toString();
			} catch(ex) {
				//If the above fails somehow, just return a blank string.
				//No need to throw or log that.
				return '';
			}
		}

		//If advanced is not true, return the string value from the 'value' field.
		return grConfiguredSensorParam.getValue('value') || '';
	},

	/**
	 *
	 * @param allSensors
	 * @returns {*}
	 * @private
	 */
	_updateAndDeleteExistingSensors : function (allSensors) {
		var grSensor, sensorName;

		grSensor = new GlideRecord('x_taniu_tan_core_tan_sensor');
		grSensor.query();

		while (grSensor.next()) {
			sensorName = grSensor.getValue('name');

			//If latest sensor import does not contain the record's sensor name, delete
			// the sensor record in the Tanium Sensor table and continue to next loop.
			if (!allSensors.hasOwnProperty(sensorName)) {
				grSensor.deleteRecord();
				continue;
			}

			try {
				//If sensor in grSensor record IS found in the latest import, populate the
				// sensor record with the latest data.
				grSensor = this._populateSensorRecord(grSensor, allSensors[sensorName]);

				//Update the sensor record.
				//NOTE: If the info in the record hasn't changed since the last update, this will
				// do nothing and not impact performance.
				grSensor.update();
				//Add, update, or delete sensor parameter records associated with this sensor
				this._addUpdateDeleteSensorParameters(
					grSensor.getValue('sys_id'),
					allSensors[sensorName]
				);

				//Remove the sensor we just add/update/deleted, from the sensors list
				delete allSensors[sensorName];
			} catch (ex) {
				gs.error(
					'Error updating Tanium Sensor with sys_id ' +
					grSensor.getUniqueValue() + ' or one of its parameters.\n' +
					'Error: ' + ex.message + '\n' +
					'Continuing to next sensor.'
				);
			}
		}

		//NOTE: This method modifies allSensors in-place, so this return is just for consistency.
		return allSensors;
	},

	/**
	 *
	 * @param sensorsToCreate
	 * @private
	 */
	_createAllMissingSensors : function (sensorsToCreate) {
		var grSensor, sensorName;

		grSensor = new GlideRecord('x_taniu_tan_core_tan_sensor');

		for (sensorName in sensorsToCreate) {
			try {
				//Prevent iteration into non-own properties
				if (!sensorsToCreate.hasOwnProperty(sensorName)) {
					continue;
				}

				//Initialize, populate, and insert the new Tanium Sensor record.
				grSensor.initialize();
				this._populateSensorRecord(grSensor, sensorsToCreate[sensorName]);
				grSensor.insert();

				//Add, update, or delete sensor parameter records associated with this sensor
				this._addUpdateDeleteSensorParameters(
					grSensor.getValue('sys_id'),
					sensorsToCreate[sensorName]
				);
			} catch (ex) {
				gs.debug(
					'Error creating Tanium Sensor with name "' + sensorName + '" or one ' +
					'of its parameters.\n' +
					'Error: ' + ex.message + '\n' +
					'Continuing to next sensor.'
				);
			}
		}
	},

	/**
	 *
	 * @param grSensor
	 * @param currentSensor
	 * @return {*}
	 * @private
	 */
	_populateSensorRecord: function (grSensor, currentSensor) {
		//This method is reused by both the "update sensor record" method and the "create sensor
		// record" method.
		var snFieldName, snFieldVal;
		/* Populate object with sensor field values */
		var sensorFields = {
			'name' : currentSensor.name.toString() //mandatory
		};
		if (currentSensor.hasOwnProperty('description') && currentSensor.description) {
			sensorFields['description'] = currentSensor.description.toString();
		}
		if (currentSensor.hasOwnProperty('category') && currentSensor.category) {
			sensorFields['category'] = currentSensor.category.toString();
		}
		if (
			currentSensor.hasOwnProperty('content_set') &&
			currentSensor.content_set &&
			(typeof currentSensor.content_set == 'object')
		) {
			if (currentSensor.content_set.hasOwnProperty('id') && currentSensor.content_set.id) {
				sensorFields['content_set_id'] = currentSensor.content_set.id.toString();
			}
			if (currentSensor.content_set.hasOwnProperty('name') && currentSensor.content_set.name) {
				sensorFields['content_set'] = currentSensor.content_set.name.toString();
			}
		}

		/* Populate GR object */
		for (snFieldName in sensorFields) {
			//Prevent iteration into non-own properties
			if (!sensorFields.hasOwnProperty(snFieldName)) {
				continue;
			}

			snFieldVal = sensorFields[snFieldName];
			grSensor.setValue(snFieldName, snFieldVal);
		}

		//NOTE: Returns grSensor WITHOUT updating. That (updating) must be done by the calling code.
		//Also modifies grSensor in-place so this return is mostly just for consistency.
		return grSensor;
	},

	/**
	 *
	 * @param sensorSysID
	 * @param sensorObj
	 * @private
	 */
	_addUpdateDeleteSensorParameters: function(sensorSysID, sensorObj) {
		var parametersObj;

		parametersObj = this._getAllParametersFromSensor(sensorObj);

		if (parametersObj) {
			//Mutates the parametersObj object in-place (deletes processed parameters).
			this._updateAndDeleteExistingSensorParameters(sensorSysID, parametersObj);
			this._createAllMissingSensorParameters(sensorSysID, parametersObj);
		}

	},

	/**
	 *
	 * @param sensorSysID
	 * @param parametersObj
	 * @return {*}
	 * @private
	 */
	_updateAndDeleteExistingSensorParameters: function(sensorSysID, parametersObj) {
		var parameterKey;
		var grSensorParameter = new GlideRecord('x_taniu_tan_core_sensor_parameter');

		grSensorParameter.addQuery('sensor', sensorSysID);
		grSensorParameter.query();

		while (grSensorParameter.next()) {
			parameterKey = grSensorParameter.getValue('key');
			//If the most recent sensor export doesn't contain a parameter for this sensor
			// with the key indicated in this record, delete the parameter record and continue
			// to the next loop.
			if (!parametersObj.hasOwnProperty(parameterKey)) {
				grSensorParameter.deleteRecord();
				continue;
			}

			//If parameter IS found in the latest import, populate the param record with the
			// latest data.
			grSensorParameter = this._populateParameterRecord(
				grSensorParameter,
				sensorSysID,
				parametersObj[parameterKey]
			);

			//Update the parameter record.
			//NOTE: If the info in the record hasn't changed since the last update, this will
			// do nothing and not impact performance.
			grSensorParameter.update();

			//Remove the parameter we just updated from the sensor parameters list
			delete parametersObj[parameterKey];
		}

		//NOTE: This method modifies parametersObj in-place, so this return is just for consistency.
		return parametersObj;
	},

	/**
	 *
	 * @param grParameter
	 * @param sensorSysID
	 * @param parameterObj
	 * @return {*}
	 * @private
	 */
	_populateParameterRecord: function(grParameter, sensorSysID, parameterObj) {
		//This method is reused by both the "update/delete parameter record" method
		// and the "create parameter record" method.
		var snFieldName, snFieldVal;
		//Populate an object with the field values to use for the sensor parameter
		var parameterFields = { //Mandatory fields
			'key' : parameterObj.key.toString(),
			//Default to key if label not present.
			'label' : (parameterObj.label ? parameterObj.label.toString() : parameterObj.key.toString()),
			'sensor' : sensorSysID
		};

		if (parameterObj.hasOwnProperty('maxChars')) {
			parameterFields['max_characters'] = parameterObj.maxChars || 0;
		}

		if (parameterObj.hasOwnProperty('helpString') && parameterObj.helpString) {
			parameterFields['help_text'] = parameterObj.helpString || '';
		}

		if (parameterObj.hasOwnProperty('promptText') && parameterObj.promptText) {
			parameterFields['prompt_text'] = parameterObj.promptText || '';
		}
		if (parameterObj.hasOwnProperty('defaultValue')) {
			parameterFields['default_value'] = parameterObj.defaultValue || '';
		}

		if (
			parameterObj.hasOwnProperty('validationExpressions') &&
			parameterObj.validationExpressions &&
			parameterObj.validationExpressions.length >= 1
		) {
			parameterFields['validation_expressions'] = JSON.stringify(parameterObj.validationExpressions);
		}

		//Populate the GlideRecord object, but don't update it - return it when finished.
		for (snFieldName in parameterFields) {
			//Prevent iteration into non-own properties
			if (!parameterFields.hasOwnProperty(snFieldName)) {
				continue;
			}

			snFieldVal = parameterFields[snFieldName];
			grParameter.setValue(snFieldName, snFieldVal);
		}

		//NOTE: Returns grParameter WITHOUT updating. That must be done by the calling code.
		//Also modifies grParameter in-place so this return is mostly just for consistency.
		return grParameter;
	},

	/**
	 *
	 * @param {string} sensorSysID
	 * @param {Object} parametersToCreate
	 * @private
	 */
	_createAllMissingSensorParameters : function (sensorSysID, parametersToCreate) {
		var parameterKey;
		var grSensorParameter = new GlideRecord('x_taniu_tan_core_sensor_parameter');

		for (parameterKey in parametersToCreate) {
			//Prevent iteration into non-own properties
			if (!parametersToCreate.hasOwnProperty(parameterKey)) {
				continue;
			}

			//Initialize, populate, and insert the new record.
			grSensorParameter.initialize();
			this._populateParameterRecord(
				grSensorParameter,
				sensorSysID,
				parametersToCreate[parameterKey]
			);
			grSensorParameter.insert();
		}
	},

	/**
	 *
	 * @param sensorObj
	 * @return {{}|boolean}
	 * @private
	 */
	_getAllParametersFromSensor: function(sensorObj) {
		var i, parametersArr;
		var parametersObj = {};

		if (
			!sensorObj.hasOwnProperty('parameter_definition') ||
			!sensorObj.parameter_definition
		) {
			return false;
		}

		try {
			parametersArr = JSON.parse(sensorObj.parameter_definition);
			parametersArr = parametersArr.parameters; //Get array of parameters
		} catch (ex) {
			gs.warn(
				'Unparseable parameter_definition node for Tanium Sensor with name ' +
				sensorObj.name + '. This is occasionally expected on a FEW parameters, but if ' +
				'this happens for all/most of them, there may be a problem.'
			);
			return false;
		}

		for (i = 0; i < parametersArr.length; i++) {
			if (
				!parametersArr[i].hasOwnProperty('key') || //Key property doesn't exist
				!parametersArr[i].key //Key property is falsy (null/undefined/blank/etc.)
			) {
				gs.debug(
					'Sensor parameter found without key value. Skipping parameter on import: \n' +
					JSON.stringify(parametersArr[i], null, 2) + '\n' +
					'Note: This is not an error. This is expected to happen in some cases. ' +
					'This log is just for auditing/troubleshooting purposes, in case ' +
					'something has gone wrong.'
				);
				continue;
			}

			parametersObj[parametersArr[i].key.toString()] = parametersArr[i];
		}

		return parametersObj;
	},

	/**
	 *
	 * @example
	 * var tic = new x_taniu_tan_core.TaniumIntegrationCore();
	 * gs.info(
	 * 	JSON.stringify(
	 * 		tic._getAllSensorDetails(), null, 2
	 * 	)
	 * );
	 * @private
	 */
	_getAllSensorDetails: function() {
		var i, responseBody, currentSensor, sensorName;
		var sensorDetails = {};
		var rGetSensorsAndParams = this._getRESTObject(
			'Tanium Integration Core',
			'Get Sensors and Parameters'
		);

		rGetSensorsAndParams.setStringParameterNoEscape('tanium_api_endpoint', this.TANIUM_API_ENDPOINT);
		responseBody = this._executeRESTCall(rGetSensorsAndParams);

		//If sensor details response is invalid, throw an error.
		if (!responseBody.hasOwnProperty('data') || responseBody.data.length <= 0) {
			throw new Error(
				'Data node missing or empty in sensor details from Tanium. Something has ' +
				'gone wrong. Response body: \n' + responseBody
			);
		}

		responseBody = responseBody.data;

		for (i = 0; i < responseBody.length; i++) {
			currentSensor = responseBody[i];
			//Prevent iteration into element that isn't related to a sensor or is missing data.
			if (
				(!currentSensor.hasOwnProperty('id') || !currentSensor.id) ||
				(!currentSensor.hasOwnProperty('name') || !currentSensor.name)
			) {
				continue;
			}

			sensorName = currentSensor.name.toString();

			//If node already exists with this sensor name, log warning and continue to next loop.
			if (sensorDetails.hasOwnProperty(sensorName)) {
				gs.warn(
					'Sensor with name ' + sensorName + ' is a duplicate. Already found ' +
					'sensor with this name. This should not be possible, as sensor names should ' +
					'be unique. This may indicate a problem in your Tanium environment.\n' +
					'Continuing to process next sensor...'
				);
				continue;
			}

			sensorDetails[sensorName] = currentSensor;
		}

		return sensorDetails;
	},

	type: 'TaniumConfiguredSensorUtil'
});
